var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"안색이 나쁘네? 에델이 들려 준 얘기가 그렇게 충격적이었어?","JPN":"顔色が悪いね。エデルの話したことがそんなにショックだった？","ENG":"You don't look so good. Was Edel's story that much of a shock to you?","TWN":"妳臉色不太好耶？艾瑟兒說的這麼令人震驚嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 헛된 연구나 일삼는 사이비 패거리가 차라리 낫죠.","JPN":"ええ。くだらない研究ばかりしているインチキ集団の方がマシでしたね。","ENG":"Yes. It was better when they were just a group of stupid researchers studying nonsense.","TWN":"是啊，還不如天天做沒用研究的邪教學會呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"상상도 못했어요. 학회가 그런 끔직한 괴물이나 숭배하는 집단이었을 줄은.","JPN":"想像もできませんでした。学会がそんな恐ろしい怪物を崇拝する集団だったなんて。","ENG":"I never imagined that the Society was an organization of psychotic worshipers of those hideous monsters.","TWN":"我完全沒有想過，學會竟然是崇拜這種可怕怪物的集團。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......게다가 에델은 저 대신 학회장직을 맡은 처지잖아요.","JPN":"……それに、エデルは私の代わりに学会長を担っている立場なのですよね。","ENG":"Besides, Edel had to become the President because I wasn't around.","TWN":"……況且艾瑟兒還代替我接任了學會長一職。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 고향을 떠나지 않았더라면 그럴 필요도 없었을 텐데......","JPN":"私が故郷を離れなければ、そんな必要も無かったのに……","ENG":"Things could have turned out differently for her if I hadn't left home.","TWN":"若不是我離開了家鄉，妳也就不需要這麼做了……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이미 지나간 일을 뭐 하러 고민해?","JPN":"もう過ぎたことを悩んでどうするの？","ENG":"What happened happened. There's no point in brooding over the past.","TWN":"都是過去的事了，有什麼好煩惱的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그냥 잊어 버려. 에델도 적성에 맞아 하는 것 같은데.","JPN":"もう忘れちゃいなって。エデルも性に合ってるみたいだし。","ENG":"Just forget it. Besides, Edel seems to like what she does.","TWN":"忘了吧。反正這工作似乎也很適合艾瑟兒。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말이 된다고 생각해요? 이런 일을 어떻게 잊고 살 수 있어요?","JPN":"できると思いますか？　こんなことを忘れて暮らすなんて。","ENG":"Do you think I could do that? How could I ever forget such things?","TWN":"妳覺得這有可能嗎？我要怎麼忘記這種事情？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"원래 떠올리기 싫은 기억은 머릿속 깊숙이 묻어 두는 거야.","JPN":"元々、思い出したくない記憶なんて頭の奥底に埋めておくものだよ。","ENG":"If you have memories that you don't want to recall, you bury them deep within your heart.","TWN":"不願回憶起的記憶本來就該深埋在腦中啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"믿었던 사람에게 배신 당했다거나, 총알 살 돈이 다 떨어졌다거나.","JPN":"信じてた人に裏切られたとか、銃弾を買うお金も無くなったとか。","ENG":"Being betrayed by someone you trusted, running out of money for ammo...","TWN":"比如說被信任的人背叛，或是買子彈的錢用完了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그런 일을 억지로 붙들고 살다 보면 머리가 갑자기 돌아버릴 수도 있거든.","JPN":"そんなことをイチイチ全部覚えてたら、頭がどうにかなっちゃうしね。","ENG":"Life is full of despair, and you'll lose your mind if you hold onto it too much.","TWN":"要是強迫自己記得這些事情，說不定哪天突然就瘋掉了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"레지나는 살면서 그런 일 겪어 본 적 없어?","JPN":"レジーナは今まで生きててそういう経験ないの？","ENG":"Haven't you had such experiences in your life, Regina?","TWN":"蕾佳娜活到現在有經歷過這種事嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"멍청한 계집애 같으니!","JPN":"馬鹿な娘ね！","ENG":"You're a disgrace!","TWN":"妳這個蠢丫頭！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"제물 손질 하나 제대로 못하면서 무슨 후계자야!","JPN":"供物も捌けないで後継者になれると思っているの！","ENG":"How could you call yourself the family heir when you can't even prepare an offering properly?","TWN":"連一個祭品都處理不好，還算什麼繼承者！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"그, 그치만 엄마...... 얘 아직 살아 있는데......","JPN":"で、でもママ……この子、まだ生きてるのに……","ENG":"B-but Mom, it's still alive...","TWN":"但、但是媽媽……那孩子還活著啊……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"더러운 배신자......! 그 배신자 놈이 우리 집안을 망쳐 버렸어!","JPN":"卑怯な裏切り者め……！　あの裏切り者のせいで我が家はメチャクチャよ！","ENG":"That filthy traitor! He ruined everything for all of us!","TWN":"骯髒的叛徒……！那個叛徒毀了我們家！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 가문이 어떤 가문인데! 배신자의 더러운 핏줄 따위에 넘겨 줄까 봐!","JPN":"マクレディー家がどんな家系だかわかっているの！？\\n裏切り者の汚れた血を引く娘なんかに譲るものか！","ENG":"He disgraced the great Family MacCready! I won't hand my family over to that filthy betrayer or his kin!","TWN":"我們是什麼家族！怎麼可以把家族交給叛徒骯髒的血脈！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};